<template>
	<div class="front-page">
		<div v-if="centerType" class="back_box">
			<el-button class="backBtn" size="mini" @click="backClick">返回</el-button>
		</div>

		<header class="front-page-header">
			<div class="front-page-header__title">
				<span class="front-pill">Used Car Browse</span>
				<h1>二手车车源</h1>
				<p>围绕品牌、型号、年份与里程重新组织浏览体验，减少旧模板堆叠，让搜索、排序与图表入口更清晰。</p>
			</div>
			<div class="front-page-header__meta">
				<span class="front-pill">共 {{ total }} 条记录</span>
				<span class="front-pill">排序 {{ sortType }} / {{ sortOrder }}</span>
			</div>
		</header>

		<section class="front-toolbar">
			<div class="front-toolbar__group">
				<el-input v-model="formSearch.brand" class="front-toolbar__search" placeholder="搜索品牌" clearable @keyup.enter.native="getList(1, curFenlei)"></el-input>
				<el-input v-model="formSearch.model1" class="front-toolbar__search" placeholder="搜索型号" clearable @keyup.enter.native="getList(1, curFenlei)"></el-input>
				<el-input v-model="formSearch.vehicleage" class="front-toolbar__search" placeholder="搜索年份" clearable @keyup.enter.native="getList(1, curFenlei)"></el-input>
				<el-button type="primary" @click="getList(1, curFenlei)">搜索</el-button>
				<el-button v-if="btnAuth('usedcar','新增')" @click="add('/index/usedcarAdd')">新增车源</el-button>
			</div>
			<div class="front-toolbar__group">
				<el-button v-if="btnAuth('usedcar','品牌统计')" @click="chartDialogShow1">品牌统计</el-button>
				<el-button v-if="btnAuth('usedcar','型号统计')" @click="chartDialogShow2">型号统计</el-button>
				<el-button v-if="btnAuth('usedcar','城市统计')" @click="chartDialogShow3">城市统计</el-button>
				<el-button v-if="btnAuth('usedcar','年份统计')" @click="chartDialogShow4">年份统计</el-button>
				<el-button v-if="btnAuth('usedcar','车辆现价')" @click="chartDialogShow5">现价统计</el-button>
				<el-button v-if="btnAuth('usedcar','里程统计')" @click="chartDialogShow6">里程统计</el-button>
			</div>
		</section>

		<section class="front-toolbar">
			<div class="front-toolbar__group">
				<el-button @click="sortClick('clicknum')">点击量</el-button>
				<el-button @click="sortClick('storeupnum')">收藏数</el-button>
				<el-button @click="sortClick('thumbsupnum')">点赞数</el-button>
			</div>
			<div class="front-toolbar__hint">通过图像主导的卡片布局浏览车源，保留原有筛选、排序与统计能力。</div>
		</section>

		<section class="front-section">
			<div v-if="dataList.length" class="front-car-grid">
				<article v-for="(item, index) in dataList" :key="index" class="front-car-card front-clickable" @click.stop="toDetail(item)">
					<div class="front-car-card__media">
						<img @click.stop="imgPreView(item.imgurl)" v-if="item.imgurl && item.imgurl.substr(0,4)=='http' && item.imgurl.split(',w').length>1" :src="item.imgurl" class="image" />
						<img @click.stop="imgPreView(item.imgurl.split(',')[0])" v-else-if="item.imgurl && item.imgurl.substr(0,4)=='http'" :src="item.imgurl.split(',')[0]" class="image" />
						<img @click.stop="imgPreView(baseUrl + (item.imgurl ? item.imgurl.split(',')[0] : ''))" v-else :src="baseUrl + (item.imgurl ? item.imgurl.split(',')[0] : '')" class="image" />
					</div>
					<div>
						<div class="front-car-card__header">
							<div class="front-car-card__title">
								<h3>{{ item.brand }}</h3>
								<p>{{ item.model1 }}</p>
							</div>
							<div class="front-car-card__price">
								<strong>{{ item.discountprice || '--' }}</strong>
								<span>现价 / 元</span>
							</div>
						</div>
						<div class="front-car-card__facts">
							<div class="front-car-card__fact">
								<div class="front-car-card__fact-label">年份</div>
								<div class="front-car-card__fact-value">{{ item.vehicleage || '--' }}</div>
							</div>
							<div class="front-car-card__fact">
								<div class="front-car-card__fact-label">里程</div>
								<div class="front-car-card__fact-value">{{ item.kilometer || '--' }}</div>
							</div>
							<div class="front-car-card__fact">
								<div class="front-car-card__fact-label">城市</div>
								<div class="front-car-card__fact-value">{{ item.city || '--' }}</div>
							</div>
						</div>
						<div class="front-car-card__footer">
							<div class="front-car-card__metrics">
								<span>已减 {{ item.originalprice || '--' }}</span>
								<span>浏览 {{ item.clicknum || 0 }}</span>
								<span>收藏 {{ item.storeupnum || 0 }}</span>
								<span>点赞 {{ item.thumbsupnum || 0 }}</span>
							</div>
							<span class="front-muted">{{ item.addtime ? item.addtime.split(' ')[0] : '' }}</span>
						</div>
					</div>
				</article>
			</div>
			<div v-else class="front-empty">暂无匹配车源</div>

			<el-pagination
				background
				id="pagination"
				class="pagination"
				:pager-count="7"
				:page-size="pageSize"
				prev-text="<"
				next-text=">"
				:hide-on-single-page="true"
				:layout='["total","prev","pager","next","sizes","jumper"].join()'
				:total="total"
				:page-sizes="pageSizes"
				@current-change="curChange"
				@size-change="sizeChange"
				@prev-click="prevClick"
				@next-click="nextClick"
			></el-pagination>
		</section>

		<el-dialog title="预览图" :visible.sync="previewVisible" width="50%">
			<img :src="previewImg" alt="" style="width: 100%;">
		</el-dialog>
		<el-dialog :visible.sync="chartVisiable1" width="800"><div id="brandChart1" style="width:100%;height:600px;"></div><span slot="footer" class="dialog-footer"><el-button @click="chartVisiable1 = false">返回</el-button></span></el-dialog>
		<el-dialog :visible.sync="chartVisiable2" width="800"><div id="model1Chart2" style="width:100%;height:600px;"></div><span slot="footer" class="dialog-footer"><el-button @click="chartVisiable2 = false">返回</el-button></span></el-dialog>
		<el-dialog :visible.sync="chartVisiable3" width="800"><div id="cityChart3" style="width:100%;height:600px;"></div><span slot="footer" class="dialog-footer"><el-button @click="chartVisiable3 = false">返回</el-button></span></el-dialog>
		<el-dialog :visible.sync="chartVisiable4" width="800"><div id="vehicleageChart4" style="width:100%;height:600px;"></div><span slot="footer" class="dialog-footer"><el-button @click="chartVisiable4 = false">返回</el-button></span></el-dialog>
		<el-dialog :visible.sync="chartVisiable5" width="800"><div id="discountpriceChart5" style="width:100%;height:600px;"></div><span slot="footer" class="dialog-footer"><el-button @click="chartVisiable5 = false">返回</el-button></span></el-dialog>
